using UnityEngine;
using UnityEngine.InputSystem;//библиотека для работы с новыми Input System

[DisallowMultipleComponent] //  Это страховка: иметь два CameraTargetController на одном объекте бессмысленно и привело бы к багам
[DefaultExecutionOrder(-100)] // -100 нам нужно, потому что Cinemachine читает позицию/поворот CameraTarget в каждом кадре. Если наш скрипт обновит поворот до Cinemachine, камера окажется в правильном месте. Если позже — на 1 кадр будет рассинхрон и возможна лёгкая дрожь. 
public class CameraTargetController : MonoBehaviour
{
    [Header("Mouse Sensitivity")]
    [SerializeField] private float sensitivityX = 0.15f; // Чувствительность по горизонтали. Обычно по горизонтали чувствительность чуть выше, чтобы было удобнее быстро поворачиваться.
    [SerializeField] private float sensitivityY = 0.12f; // Обычно по вертикали чувствительность чуть меньше, чтобы было удобнее целиться.
    [SerializeField] private bool invertY = false; //  Если true, то движение мыши вверх будет увеличивать угол поворота по X (поднимать камеру), а движение вниз — уменьшать (опускать камеру). Если false, то наоборот: движение вверх будет опускать камеру, а вниз — поднимать. Это просто вопрос предпочтений игрока.

    [Header("Vertical Clamp (Pitch)")]
    [SerializeField] private float minPitch = -35f;// ограничение угла поворота камеры вниз. Обычно не стоит позволять камере смотреть прямо вниз, чтобы не было неприятного ощущения "крутого виража". -35 градусов — это примерно оптимальный угол для большинства игр от третьего лица.
    [SerializeField] private float maxPitch = 70f; // ограничение угла поворота камеры вверх. Обычно стоит позволять камере смотреть выше горизонта, чтобы было удобно целиться по воздуху, но не слишком высоко, чтобы не было ощущения "крутого виража". 70 градусов — это примерно оптимальный угол для большинства игр от третьего лица.

    [Header("Cursor")]
    [SerializeField] private bool lockCursorOnStart = true; // флаг, который определяет, будет ли курсор мыши заблокирован и скрыт при запуске игры. Обычно для игр от третьего лица это желательно, чтобы курсор не отвлекал игрока и не мешал управлению камерой.

    private float yaw; // угол поворота камеры по горизонтали (вокруг оси Y). Обычно его называют "yaw" (рыскание), потому что он отвечает за вращение камеры влево-вправо, как будто голова персонажа поворачивается в эти стороны.
    private float pitch; // угол поворота камеры по вертикали (вокруг оси X). Обычно его называют "pitch" (тангаж), потому что он отвечает за вращение камеры вверх-вниз, как будто голова персонажа наклоняется в эти стороны.

    private void Start()
    {
        Vector3 e = transform.eulerAngles; //transform.eulerAngles это текущий угол поворота объекта в мировых координатах, представленный в виде вектора (x, y, z), где x — это угол поворота вокруг оси X (pitch), y — это угол поворота вокруг оси Y (yaw), а z — это угол поворота вокруг оси Z (roll). В нашем случае roll не используется, так как камера обычно не наклоняется в стороны.


        yaw = e.y; // кеширование текущего угла поворота по горизонтали (yaw) и вертикали (pitch) в начале игры. Это нужно, чтобы при запуске игры камера не "прыскала" в какую-то странную позицию, а продолжала смотреть в том же направлении, что и в редакторе.
        pitch = NormalizePitch(e.x); // функция NormalizePitch нужна, чтобы корректно обработать углы поворота, которые могут быть представлены в виде 0-360 градусов. Например, если камера смотрит немного вниз, то угол по X может быть 350 градусов, что эквивалентно -10 градусам. NormalizePitch преобразует такие углы в диапазон от -180 до 180 градусов, чтобы было удобнее работать с ними и применять ограничения.

        if (lockCursorOnStart)
        {
            Cursor.lockState = CursorLockMode.Locked; //Cursor.lockState = CursorLockMode.Locked; — это команда, которая блокирует курсор мыши в центре экрана. Это означает, что курсор не будет перемещаться по экрану и не будет виден игроку. Вместо этого, движение мыши будет использоваться для управления камерой, а не для перемещения курсора. Это обычно используется в играх от первого или третьего лица, чтобы обеспечить более интуитивное управление камерой и избежать отвлекающего фактора от видимого курсора.CursorLockMode.Locked — это один из режимов блокировки курсора, который полностью блокирует его в центре экрана. Другие режимы включают CursorLockMode.None (курсор свободен и видим) и CursorLockMode.Confined (курсор ограничен рамками окна, но видим).  

            Cursor.visible = false; //Cursor.visible = false; — это команда, которая делает курсор мыши невидимым для игрока. Это означает, что даже если курсор технически существует и может быть перемещен, он не будет отображаться на экране. Это обычно используется вместе с Cursor.lockState = CursorLockMode.Locked; в играх от первого или третьего лица, чтобы обеспечить более погруженное управление камерой и избежать отвлекающего фактора от видимого курсора. Когда курсор заблокирован и скрыт, игрок может свободно перемещать мышь для управления камерой, не беспокоясь о том, что курсор будет мешать или отвлекать внимание.
        }
    }

    private void Update()
    {
        if (Mouse.current == null) return; // Проверка на случай, если в системе нет мыши (например, на мобильных устройствах). Если Mouse.current равен null, то мы просто не будем обрабатывать ввод и позволим камере оставаться в текущем положении.

        Vector2 delta = Mouse.current.delta.ReadValue();// Чтение значения изменения положения мыши (delta) с помощью новой Input System. Mouse.current.delta возвращает вектор (x, y), который показывает, насколько мышь переместилась по горизонтали (x) и вертикали (y) с последнего кадра. Этот вектор используется для обновления углов поворота камеры.

        yaw += delta.x * sensitivityX; // Обновление угла поворота по горизонтали (yaw) на основе изменения положения мыши по горизонтали (delta.x) и чувствительности (sensitivityX). Чем больше значение sensitivityX, тем быстрее будет вращаться камера при движении мыши. Обычно по горизонтали чувствительность чуть выше, чтобы было удобнее быстро поворачиваться.
        pitch += (invertY ? 1f : -1f) * delta.y * sensitivityY; // Обновление угла поворота по вертикали (pitch) на основе изменения положения мыши по вертикали (delta.y), чувствительности (sensitivityY) и флага инверсии (invertY). Если invertY равно true, то движение мыши вверх будет увеличивать угол поворота по X (поднимать камеру), а движение вниз — уменьшать (опускать камеру). Если false, то наоборот: движение вверх будет опускать камеру, а вниз — поднимать. Обычно по вертикали чувствительность чуть меньше, чтобы было удобнее целиться.
        pitch = Mathf.Clamp(pitch, minPitch, maxPitch); // Ограничение угла поворота по вертикали (pitch) в диапазоне от minPitch до maxPitch с помощью функции Mathf.Clamp. Это нужно, чтобы предотвратить слишком сильное наклонение камеры вверх или вниз, что может вызвать неприятные ощущения "крутого виража". Обычно для игр от третьего лица оптимальные значения minPitch и maxPitch составляют примерно -35 и 70 градусов соответственно.
    }

    private void LateUpdate()
    {
        transform.rotation = Quaternion.Euler(pitch, yaw, 0f); // Применение обновленных углов поворота (pitch и yaw) к трансформу камеры в функции LateUpdate. LateUpdate вызывается после всех Update, что гарантирует, что камера будет обновляться после того, как все объекты в сцене обновят свои позиции и состояния. Это важно для предотвращения рассинхрона между движением камеры и движением персонажа или других объектов, за которыми она следит. Quaternion.Euler(pitch, yaw, 0f) создает кватернион из углов Эйлера, где pitch — это угол поворота по X (тангаж), yaw — это угол поворота по Y (рыскание), а roll (поворот по Z) устанавливается в 0, так как мы не используем его в этом случае.
    }

    private static float NormalizePitch(float angle)// принимаем сюда угол в градусах, который может быть в диапазоне от 0 до 360, и преобразуем его в диапазон от -180 до 180 градусов. Это нужно, чтобы было удобнее работать с углами поворота по вертикали (pitch) и применять ограничения. Например, если угол равен 350 градусов, то он эквивалентен -10 градусам, что означает, что камера смотрит немного вниз. Если угол равен 30 градусов, то он остается 30 градусами, что означает, что камера смотрит немного вверх. Если угол равен 180 градусов, то он остается 180 градусами, что означает, что камера смотрит прямо вперед. Если угол равен 270 градусов, то он эквивалентен -90 градусам, что означает, что камера смотрит прямо вниз.
    {
        if (angle > 180f) angle -= 360f;// Если угол больше 180 градусов, то вычитаем 360 градусов, чтобы получить эквивалентный угол в диапазоне от -180 до 180 градусов. Например, если угол равен 350 градусов, то после вычитания 360 градусов он станет -10 градусами, что означает, что камера смотрит немного вниз.
        return angle;// Возвращаем нормализованный угол, который теперь находится в диапазоне от -180 до 180 градусов. Например, если входной угол был 350 градусов, то выходной угол будет -10 градусами. Если входной угол был 30 градусов, то выходной угол будет 30 градусами. Если входной угол был 180 градусов, то выходной угол будет 180 градусами. Если входной угол был 270 градусов, то выходной угол будет -90 градусами.
    }
}
